const failRetryCount = videoData.failRetryCount || 0;
const originalVideoPrompt = videoData.videoPrompt || $('Set - Proposal Data').item?.json?.videoPrompt || '';
const originalData = { videoPrompt: originalVideoPrompt, leadName: videoData.leadName || $('Set - Proposal Data').item?.json?.leadName || '', leadEmail: videoData.leadEmail || $('Set - Proposal Data').item?.json?.leadEmail || '', leadCompany: videoData.leadCompany || $('Set - Proposal Data').item?.json?.leadCompany || '', recordId: videoData.recordId || $('Set - Proposal Data').item?.json?.recordId || '' };
const state = (videoData.data?.state || '').toLowerCase();
const failCode = videoData.data?.failCode;
const failMsg = videoData.data?.failMsg;
if (state === 'fail' || state === 'failed' || state === 'error' || failCode) {
  if (failRetryCount < 1) { return { json: { ...originalData, ...videoData, needsRetry: true, skipVideo: false, videoReady: false, failRetryCount: failRetryCount + 1, retryCount: 0 } }; }
  else { return { json: { ...originalData, ...videoData, skipVideo: true, videoReady: true, needsRetry: false, failRetryCount: failRetryCount } }; }
}
if (retryCount >= MAX_RETRIES) { return { json: { ...originalData, ...videoData, skipVideo: true, videoReady: true, needsRetry: false, retryCount: 0 } }; }
const resultJson = videoData.data?.resultJson;
const completeTime = videoData.data?.completeTime;
const isComplete = state === 'success' || state === 'completed' || (resultJson && resultJson.trim() !== '') || (completeTime !== null && completeTime !== undefined && !failCode);
if (isComplete) {
  let resultUrls = [];
  try { if (resultJson && resultJson.trim() !== '') { const parsed = JSON.parse(resultJson); resultUrls = parsed.resultUrls || parsed.urls || []; } } catch (e) {}
  return { json: { ...originalData, ...videoData, skipVideo: false, videoReady: true, needsRetry: false, retryCount: 0, data: { ...videoData.data, response: { resultUrls: resultUrls } } } };
}
return { json: { ...originalData, ...videoData, skipVideo: false, videoReady: false, needsRetry: false, continuePolling: true, retryCount: retryCount + 1, failRetryCount: failRetryCount } };

